mapper.select:
SELECT id, device_id, record_year, record_month, actual_kwh, theoretical_kwh,
source, created_by, created_at, updated_at, is_deleted
FROM solar_monthly_records
WHERE device_id = #{deviceId}
    AND record_year = #{year}
    AND record_month = #{month}
    AND is_deleted =0
LIMIT 1

SELECT COALESCE(SUM(actual_kwh), 0)
FROM solar_monthly_records
WHERE record_year = #{recordYear}
AND record_month = #{recordMonth}
AND is_deleted = 0

SELECT COUNT(1) > 0
FROM solar_monthly_records
WHERE record_year = #{recordYear}
AND record_month = #{recordMonth}
AND is_deleted = 0
